fn fetch_data() -> String {
    let data = reqwest::get("https://api.example.com")
        .await // Error: `await` is only allowed in `async` functions
        .unwrap();
    data.text().await.unwrap()
}

fixes.code:
async fn fetch_data() -> String {
    let resp = reqwest::get("https://api.example.com")
        .await
        .unwrap();
    resp.text().await.unwrap()
}

fn fetch_data() -> String {
    let rt = tokio::runtime::Runtime::new().unwrap();
    rt.block_on(async {
        let resp = reqwest::get("https://api.example.com")
            .await
            .unwrap();
        resp.text().await.unwrap()
    })
}
